fn main() {
    let vec1 = fill_vec();

    println!("{} has length {}, with contents: {:?}", "vec1", vec1.len(), vec1);
}

fn fill_vec() -> Vec<i32> {
    let mut vec = vec![22, 44, 66, 11];
